-- ----------------------------------------------------------------------------
-- vw_events: Table: Events — top-level container (a festival, food bank shift, conference, etc.).
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_events WITH (security_invoker = ON) AS
SELECT
  t.event_id,
  t.name,                                                                       -- Display name of the event.
  t.event_date,
  calc_events_shift_count(t.event_id) AS shift_count,                           -- Total shifts attached to this event.
  calc_events_total_slots_needed(t.event_id) AS total_slots_needed,             -- Sum of needed-count across all shifts in this event.
  calc_events_total_slots_filled(t.event_id) AS total_slots_filled,             -- Sum of filled-count across all shifts in this event.
  calc_events_coverage_percent(t.event_id) AS coverage_percent,                 -- TotalSlotsFilled / TotalSlotsNeeded (0..1).
  calc_events_staffing_grade(t.event_id) AS staffing_grade                      -- A-F letter grade from CoveragePercent. A: >=95%, B: >=85%, C: >=70%, D: >=50%, F: below.
FROM events t;

-- ----------------------------------------------------------------------------
-- vw_volunteers: Table: Volunteers — people available to be slotted into shifts.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_volunteers WITH (security_invoker = ON) AS
SELECT
  t.volunteer_id,
  calc_volunteers_name(t.volunteer_id) AS name,                                 -- Display name.
  t.first_name,
  t.last_name,
  t.email_address,                                                              -- Used as the click-to-login identity.
  t.reliability_score,                                                          -- 0..1 — coordinator's confidence the volunteer will show up. Drives per-shift coverage weighting.
  t.max_hours,                                                                  -- Volunteer's stated maximum hours for this scheduling period.
  calc_volunteers_assignment_count(t.volunteer_id) AS assignment_count,         -- Number of shifts this volunteer is assigned to.
  calc_volunteers_assigned_hours(t.volunteer_id) AS assigned_hours,             -- Sum of DurationHours across this volunteer's assigned shifts.
  calc_volunteers_load_status(t.volunteer_id) AS load_status                    -- under | ok | over. Under: <50% of MaxHours. Over: >100%. Otherwise ok.
FROM volunteers t;

-- ----------------------------------------------------------------------------
-- vw_shifts: Table: Shifts — a time block within an event needing N people with a required skill.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_shifts WITH (security_invoker = ON) AS
SELECT
  t.shift_id,
  t.name,                                                                       -- Short label (e.g. "Setup Morning").
  t.event,                                                                      -- Parent event.
  calc_shifts_event_name(t.shift_id) AS event_name,
  t.required_skill,                                                             -- Free-text skill tag (e.g. "setup", "intake", "food-handler").
  t.duration_hours,                                                             -- Length of the shift in hours; drives per-volunteer load.
  t.needed_count,                                                               -- How many volunteers the coordinator wants on this shift.
  calc_shifts_filled_count(t.shift_id) AS filled_count,                         -- Number of volunteers currently assigned.
  calc_shifts_coverage_status(t.shift_id) AS coverage_status                    -- understaffed | covered | overstaffed.
FROM shifts t;

-- ----------------------------------------------------------------------------
-- vw_assignments: Table: Assignments — a volunteer slotted into a shift. Join table between Volunteers and Shifts (ERB does not allow direct many-to-many).
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_assignments WITH (security_invoker = ON) AS
SELECT
  t.assignment_id,
  calc_assignments_name(t.assignment_id) AS name,                               -- Display label (VolunteerName @ ShiftName).
  t.volunteer,
  t.shift,
  calc_assignments_volunteer_name(t.assignment_id) AS volunteer_name,
  calc_assignments_shift_name(t.assignment_id) AS shift_name,
  calc_assignments_shift_duration_hours(t.assignment_id) AS shift_duration_hours-- Pulled through to support per-volunteer AssignedHours aggregation.
FROM assignments t;

